const axios = require('axios');

class OAuthClient {
  constructor(config) {
    this.config = config;
    this.accessToken = null;
    this.storageKey = 'oauth_access_token';
  }

  async authorize() {
    const url = `https://example.com/oauth/authorize?client_id=${this.config.clientId}&response_type=token&redirect_uri=${this.config.redirectUri}&scope=read`;
    window.location.href = url;
  }

  parseAccessToken(url) {
    const queryString = new URL(url).hash.split('&')[0].split('=')[1];
    this.accessToken = queryString;
    return this.accessToken;
  }

  storeAccessToken(token) {
    localStorage.setItem(this.storageKey, token);
  }

  loadAccessToken() {
    try {
      return localStorage.getItem(this.storageKey);
    } catch (e) {}
    return null;
  }

  async makeApiCall(url, method = 'GET', data = {}) {
    const headers = { Authorization: `Bearer ${this.accessToken}` };
    try {
      const response = await axios({
        method,
        url,
        headers,
        params: data
      });
      return response.data;
    } catch (e) {
      console.error(e);
      throw e;
    }
  }
}

class SinglePageApplication {
  constructor(config) {
    this.oauthClient = new OAuthClient(config);
    const queryString = window.location.href.split('#')[1];
    if (queryString && queryString.startsWith('access_token')) {
      this.oauthClient.parseAccessToken(queryString);
      this.oauthClient.storeAccessToken(this.oauthClient.accessToken);
    }
    this.accessToken = this.oauthClient.loadAccessToken();
  }

  async makeApiCall(url, method = 'GET', data = {}) {
    return await this.oauthClient.makeApiCall(url, method, data);
  }
}

